class Solution:
    def summaryRanges(self, nums):
        res = []
        if not nums:
            return res
        start = nums[0]
        prev = nums[0]
        for x in nums[1:]:
            if x == prev + 1:
                prev = x
                continue
            res.append(str(start) if start == prev else str(start) + '->' + str(prev))
            start = prev = x
        res.append(str(start) if start == prev else str(start) + '->' + str(prev))
        return res

