var summaryRanges = function(nums) {
    const res = [];
    if (nums.length === 0) return res;
    let start = nums[0];
    let prev = nums[0];
    for (let i = 1; i < nums.length; i++) {
        const x = nums[i];
        if (x === prev + 1) {
            prev = x;
            continue;
        }
        res.push(start === prev ? String(start) : start + '->' + prev);
        start = prev = x;
    }
    res.push(start === prev ? String(start) : start + '->' + prev);
    return res;
};
